// Period configuration helpers.
//
// The legacy code relied on a global `getCurrentPeriodConfig()` returning
// `{ label, multiplier }` where `multiplier` was the number of periods per
// year. The pure engine receives an explicit `periodConfig` object instead.
//
// To stay compatible with both shapes seen in the codebase:
//   - index.html / batch/index.html: `{ label, multiplier }`
//   - payroll/index.html: `{ label, periods }`
// the helpers below normalise either shape into `{ label, periodsPerYear }`.

const DEFAULT_PERIODS_PER_YEAR = {
  Annual: 1,
  Monthly: 12,
  Fortnightly: 26,
  Weekly: 52
};

export function normalisePeriodConfig(input) {
  if (!input) {
    return { label: 'Annual', periodsPerYear: 1 };
  }
  const label = input.label || 'Annual';
  const periodsPerYear =
    input.periodsPerYear ||
    input.multiplier ||
    input.periods ||
    DEFAULT_PERIODS_PER_YEAR[label] ||
    1;
  return { label, periodsPerYear };
}

export function convertFromAnnual(annualAmount, periodConfig) {
  const { periodsPerYear } = normalisePeriodConfig(periodConfig);
  return annualAmount / periodsPerYear;
}

export function convertToAnnual(amount, periodConfig) {
  const { periodsPerYear } = normalisePeriodConfig(periodConfig);
  return amount * periodsPerYear;
}

// Year-specific PRSI rate resolvers (legacy L136–149). The `period` argument
// is the half-year selector: 'jan-sep' or 'oct-dec'.
export function get2024PRSIRate(period) {
  return period === 'jan-sep' ? 0.040 : 0.041;
}

export function get2025PRSIRate(period) {
  return period === 'jan-sep' ? 0.041 : 0.042;
}

export function get2026PRSIRate(period) {
  return period === 'jan-sep' ? 0.042 : 0.0435;
}

export function resolvePRSIRate(year, period, fallbackRate) {
  const key = typeof year === 'string' ? year : String(year);
  if (key === '2024') return get2024PRSIRate(period);
  if (key === '2025') return get2025PRSIRate(period);
  if (key === '2026') return get2026PRSIRate(period);
  return fallbackRate;
}
