// Pure Net <-> Gross orchestration
// All inputs are explicit; no DOM, no globals.

import { roundToThree } from './rounding.js';
import { calculatePAYE, calculatePAYEWithBreakdown } from './paye.js';
import { calculateUSCWithBreakdown } from './usc.js';
import { calculatePRSIWithBreakdown } from './prsi.js';
import { calculateTaxCredits } from './credits.js';

/**
 * Calculate net pay from gross income.
 * @param {number} grossIncome - Annual gross income in EUR.
 * @param {object} opts
 * @param {('2024'|'2025'|'2026'|number)} opts.year
 * @param {string} [opts.status='single'] - single | married | marriedOneWorking | singleParent | manual
 * @param {string} [opts.period] - 'jan-sep' | 'oct-dec' (PRSI sub-period)
 * @param {object} opts.periodConfig - { label, periodsPerYear } - frequency context
 * @param {number} [opts.manualCutOff]
 * @param {number} [opts.manualTaxCredits]
 * @returns {object}
 */
export function calculateNetFromGross(grossIncome, opts = {}) {
    const {
        year,
        status = 'single',
        period,
        periodConfig,
        manualCutOff,
        manualTaxCredits
    } = opts;

    const paye = calculatePAYE(grossIncome, { year, status, manualCutOff });
    const payeBreakdown = calculatePAYEWithBreakdown(grossIncome, {
        year,
        status,
        manualCutOff,
        manualTaxCredits,
        periodConfig
    });
    const uscBreakdown = calculateUSCWithBreakdown(grossIncome, { year });
    const usc = uscBreakdown.total;
    const prsiBreakdown = calculatePRSIWithBreakdown(grossIncome, {
        year,
        period,
        periodConfig
    });
    const prsi = prsiBreakdown.total;
    const taxCredits = calculateTaxCredits({ year, status, manualTaxCredits });

    const payeAfterCredits = roundToThree(Math.max(0, paye - taxCredits));
    const totalDeductions = roundToThree(payeAfterCredits + usc + prsi);
    const netIncome = roundToThree(grossIncome - totalDeductions);
    // Match legacy behaviour exactly: 0 gross → NaN → JSON null.
    const takeHomePercentage = roundToThree((netIncome / grossIncome) * 100);

    return {
        grossIncome: roundToThree(grossIncome),
        paye: payeAfterCredits,
        payeBreakdown,
        usc,
        uscBreakdown,
        prsi,
        prsiBreakdown,
        taxCredits: roundToThree(taxCredits),
        totalDeductions,
        netIncome,
        takeHomePercentage
    };
}

/**
 * Reverse-solve gross income from a target net income, preserving the
 * legacy multiplicative-feedback algorithm (1.4x seed, 100 iter, 0.001 tol,
 * 0.5 damping) for behavioural parity with the v1 engine.
 *
 * @param {number} targetNetIncome
 * @param {object} opts - same shape as calculateNetFromGross opts
 * @returns {object} same shape as calculateNetFromGross + { targetNetIncome, iterations, converged? }
 */
export function calculateGrossFromNet(targetNetIncome, opts = {}) {
    let grossEstimate = roundToThree(targetNetIncome * 1.4);
    let iterations = 0;
    const maxIterations = 100;
    const tolerance = 0.001;

    while (iterations < maxIterations) {
        const result = calculateNetFromGross(grossEstimate, opts);
        const difference = roundToThree(result.netIncome - targetNetIncome);

        if (Math.abs(difference) <= tolerance) {
            return {
                ...result,
                targetNetIncome: roundToThree(targetNetIncome),
                iterations: iterations + 1
            };
        }

        const adjustmentFactor = result.netIncome === 0
            ? 0
            : difference / result.netIncome;
        grossEstimate = roundToThree(grossEstimate * (1 - adjustmentFactor * 0.5));
        iterations++;
    }

    const finalResult = calculateNetFromGross(grossEstimate, opts);
    return {
        ...finalResult,
        targetNetIncome: roundToThree(targetNetIncome),
        iterations,
        converged: false
    };
}
