// Pure PRSI calculations (legacy js/calculator-core.js L239–394).

import { ratesForYear } from './rates.js';
import { roundToThree, roundToTwo } from './rounding.js';
import { normalisePeriodConfig, resolvePRSIRate } from './period.js';
import { formatCurrency } from './format.js';

const DEFAULT_CREDIT_BANDS = {
  Weekly: { min: 352.01, max: 424.00, maxCredit: 12.00, threshold: 352.00 },
  Fortnightly: { min: 704.01, max: 848.00, maxCredit: 24.00, threshold: 704.00 },
  Monthly: { min: 1525.34, max: 1837.33, maxCredit: 52.00, threshold: 1525.33 },
  Annual: { min: 18304.01, max: 22048.00, maxCredit: 624.00, threshold: 18304.00 }
};

/**
 * @param {number} grossIncome
 * @param {object} opts
 * @param {string|number} opts.year
 * @param {string} opts.period            'jan-sep' | 'oct-dec' (year-period for PRSI rate)
 * @param {object} opts.periodConfig      { label, periodsPerYear }
 */
export function calculatePRSIWithBreakdown(grossIncome, opts = {}) {
  const { year, period: yearPeriod, periodConfig } = opts;
  const yearKey = typeof year === 'string' ? year : String(year);
  const rates = ratesForYear(year);
  const periodCfg = normalisePeriodConfig(periodConfig);
  const periodMultiplier = periodCfg.periodsPerYear;
  const periodGross = grossIncome / periodMultiplier;

  const prsiBreakdown = {
    total: 0,
    bands: [],
    periodGross: roundToThree(periodGross),
    period: periodCfg.label
  };

  const creditBands = rates.PRSI_CREDIT_BANDS || DEFAULT_CREDIT_BANDS;
  const creditConfig = creditBands[periodCfg.label];

  // A0 band: Below minimum PRSI threshold
  if (periodGross <= creditConfig.threshold) {
    const a0Min = periodCfg.label === 'Weekly' ? 38.00 :
                  periodCfg.label === 'Fortnightly' ? 76.00 :
                  periodCfg.label === 'Monthly' ? 164.65 :
                  1976.00; // Annual
    const bandCode = periodGross < a0Min ? 'Below A0' : 'A0';
    const description = periodGross < a0Min ? 'Below minimum threshold' : 'No employee PRSI';

    prsiBreakdown.bands.push({
      code: bandCode,
      range: bandCode === 'Below A0'
        ? `Under ${formatCurrency(a0Min)}`
        : `${formatCurrency(a0Min)} \u2212 ${formatCurrency(creditConfig.threshold)}`,
      rate: 0,
      periodPRSI: 0,
      credit: 0,
      netPRSI: 0,
      description
    });
    return prsiBreakdown;
  }

  // AX band: Credit band with tapered credit
  if (periodGross > creditConfig.threshold && periodGross <= creditConfig.max) {
    const prsiRate = resolvePRSIRate(yearKey, yearPeriod, rates.PRSI_RATES.employee.rate);
    const periodPRSI = periodGross * prsiRate;

    // Excel formula: =ROUND(MAX(0,MIN(maxCredit,maxCredit-((periodGross-threshold)/6))),2)
    const credit = roundToTwo(Math.max(0, Math.min(
      creditConfig.maxCredit,
      creditConfig.maxCredit - ((periodGross - creditConfig.min) / 6)
    )));
    const netPeriodPRSI = Math.max(0, periodPRSI - credit);

    prsiBreakdown.bands.push({
      code: 'AX',
      range: `${formatCurrency(creditConfig.min)} \u2212 ${formatCurrency(creditConfig.max)}`,
      rate: prsiRate,
      periodPRSI: roundToThree(periodPRSI),
      credit,
      netPRSI: roundToThree(netPeriodPRSI),
      description: `${(prsiRate * 100).toFixed(1)}% with tapered credit`
    });

    prsiBreakdown.total = roundToThree(netPeriodPRSI * periodMultiplier);
    return prsiBreakdown;
  }

  // AL band: Above credit band up to AL threshold
  const alMaxWeekly = yearKey === '2024'
    ? (yearPeriod === 'jan-sep' ? 441.00 : 496.00)
    : 527.00;
  const alMax = periodCfg.label === 'Weekly' ? alMaxWeekly :
                periodCfg.label === 'Fortnightly' ? alMaxWeekly * 2 :
                periodCfg.label === 'Monthly' ? roundToTwo(alMaxWeekly * 4.333) :
                alMaxWeekly * 52;

  if (periodGross > creditConfig.max && periodGross <= alMax) {
    const prsiRate = resolvePRSIRate(yearKey, yearPeriod, rates.PRSI_RATES.employee.rate);
    const periodPRSI = periodGross * prsiRate;
    prsiBreakdown.bands.push({
      code: 'AL',
      range: `${formatCurrency(creditConfig.max)} \u2212 ${formatCurrency(alMax)}`,
      rate: prsiRate,
      periodPRSI: roundToThree(periodPRSI),
      credit: 0,
      netPRSI: roundToThree(periodPRSI),
      description: `${(prsiRate * 100).toFixed(1)}% standard rate`
    });
    prsiBreakdown.total = roundToThree(periodPRSI * periodMultiplier);
    return prsiBreakdown;
  }

  // A1 band: Over AL threshold
  if (periodGross > alMax) {
    const prsiRate = resolvePRSIRate(yearKey, yearPeriod, rates.PRSI_RATES.employee.rate);
    const periodPRSI = periodGross * prsiRate;

    const a1ThresholdWeekly = yearKey === '2024'
      ? (yearPeriod === 'jan-sep' ? 441.00 : 496.00)
      : 527.00;
    const a1Threshold = periodCfg.label === 'Weekly' ? a1ThresholdWeekly :
                        periodCfg.label === 'Fortnightly' ? a1ThresholdWeekly * 2 :
                        periodCfg.label === 'Monthly' ? roundToTwo(a1ThresholdWeekly * 4.333) :
                        a1ThresholdWeekly * 52;

    prsiBreakdown.bands.push({
      code: 'A1',
      range: `Over ${formatCurrency(a1Threshold)}`,
      rate: prsiRate,
      periodPRSI: roundToThree(periodPRSI),
      credit: 0,
      netPRSI: roundToThree(periodPRSI),
      description: `${(prsiRate * 100).toFixed(1)}% standard rate`
    });
    prsiBreakdown.total = roundToThree(periodPRSI * periodMultiplier);
    return prsiBreakdown;
  }

  return prsiBreakdown;
}

export function calculatePRSI(grossIncome, opts) {
  return calculatePRSIWithBreakdown(grossIncome, opts).total;
}
