// Shared rounding helpers used across the engine.
// Behaviour ported verbatim from legacy js/calculator-core.js L132.
export function roundToThree(value) {
  return Math.round(value * 1000) / 1000;
}

// Two-decimal rounding used for the PRSI tapered credit (legacy L299) and
// for the AL/A1 monthly threshold derivation (legacy L330, L376).
export function roundToTwo(value) {
  return Math.round(value * 100) / 100;
}
