// Pure tax-credit calculation (legacy js/calculator-core.js L494–512).

import { ratesForYear } from './rates.js';
import { roundToThree } from './rounding.js';

/**
 * @param {object} opts
 * @param {string|number} opts.year
 * @param {string} opts.status            'single'|'married'|'marriedOneWorking'|'singleParent'|'manual'
 * @param {number|null} [opts.manualTaxCredits]  required when status === 'manual'
 * @returns {number}
 */
export function calculateTaxCredits({ year, status = 'single', manualTaxCredits } = {}) {
  if (status === 'manual') {
    const yearKey = typeof year === 'string' ? year : String(year);
    const defaultCredits = yearKey === '2024' ? 3750 : 4000;
    const manualCredits =
      manualTaxCredits != null && !Number.isNaN(parseFloat(manualTaxCredits))
        ? parseFloat(manualTaxCredits)
        : defaultCredits;
    return roundToThree(manualCredits || defaultCredits);
  }

  const { TAX_CREDITS } = ratesForYear(year);
  switch (status) {
    case 'married':
      return TAX_CREDITS.marriedCredit + (TAX_CREDITS.employeeCredit * 2);
    case 'marriedOneWorking':
      return TAX_CREDITS.marriedOneWorkingCredit + TAX_CREDITS.employeeCredit;
    case 'singleParent':
      return TAX_CREDITS.personalCredit + TAX_CREDITS.employeeCredit + TAX_CREDITS.singleParentCredit;
    default:
      return TAX_CREDITS.personalCredit + TAX_CREDITS.employeeCredit;
  }
}
