// Browser-globals shim — preserves the legacy script-tag API.
//
// The pure engine in src/engine/* takes explicit parameters and has no
// dependency on the DOM or page-level globals. The historic call sites
// (index.html, batch/index.html, payroll/*.js) still rely on:
//
//   * the named top-level globals  (selectedYear, selected2024Period, …)
//   * the page-defined helpers     (getCurrentPeriodConfig, convertFromAnnual, …)
//   * the DOM inputs               (#manualCutOffPoint, #manualTaxCredits)
//
// This shim is the single place that bridges those legacy expectations to
// the pure engine. Once each calling page is migrated to pass parameters
// explicitly (out of scope this sprint), this file can be deleted.
//
// IMPORTANT: this file has SIDE EFFECTS — it assigns 15+ names to `window`
// (or to `globalThis` in test environments). It is the Vite library-mode
// entry point and produces js/calculator-core.js.

import {
    TAX_RATES,
    ratesForYear,
    updateTaxRatesForYear as engineUpdateTaxRatesForYear
} from '../engine/rates.js';
import { roundToThree, roundToTwo } from '../engine/rounding.js';
import {
    normalisePeriodConfig,
    convertFromAnnual as engineConvertFromAnnual,
    convertToAnnual as engineConvertToAnnual,
    get2024PRSIRate as engineGet2024PRSIRate,
    get2025PRSIRate as engineGet2025PRSIRate,
    get2026PRSIRate as engineGet2026PRSIRate
} from '../engine/period.js';
import { calculateTaxCredits as engineCalculateTaxCredits } from '../engine/credits.js';
import {
    calculatePAYE as engineCalculatePAYE,
    calculatePAYEWithBreakdown as engineCalculatePAYEWithBreakdown
} from '../engine/paye.js';
import {
    calculateUSC as engineCalculateUSC,
    calculateUSCWithBreakdown as engineCalculateUSCWithBreakdown
} from '../engine/usc.js';
import {
    calculatePRSI as engineCalculatePRSI,
    calculatePRSIWithBreakdown as engineCalculatePRSIWithBreakdown
} from '../engine/prsi.js';
import {
    calculateNetFromGross as engineCalculateNetFromGross,
    calculateGrossFromNet as engineCalculateGrossFromNet
} from '../engine/netgross.js';
import {
    formatCurrency,
    formatNumber,
    formatPercentage
} from '../engine/format.js';

// Resolve the target object once; works in browser (window) and node tests.
const target = (typeof window !== 'undefined') ? window
              : (typeof globalThis !== 'undefined') ? globalThis
              : {};

// -----------------------------------------------------------------------
// Legacy-global readers
// -----------------------------------------------------------------------

function readGlobal(name, fallback) {
    if (typeof target[name] !== 'undefined') return target[name];
    if (typeof globalThis !== 'undefined' && typeof globalThis[name] !== 'undefined') {
        return globalThis[name];
    }
    return fallback;
}

function currentYear() { return readGlobal('selectedYear', '2025'); }
function current2024Period() { return readGlobal('selected2024Period', 'oct-dec'); }
function current2025Period() { return readGlobal('selected2025Period', 'oct-dec'); }
function current2026Period() { return readGlobal('selected2026Period', 'jan-sep'); }

function yearPeriodForYear(year) {
    const k = typeof year === 'string' ? year : String(year);
    if (k === '2024') return current2024Period();
    if (k === '2025') return current2025Period();
    if (k === '2026') return current2026Period();
    return undefined;
}

function currentPeriodConfig() {
    const fn = readGlobal('getCurrentPeriodConfig', null);
    if (typeof fn === 'function') {
        const raw = fn();
        return normalisePeriodConfig(raw);
    }
    return normalisePeriodConfig({ label: 'Annual', periodsPerYear: 1 });
}

function readDomNumber(id) {
    if (typeof document === 'undefined') return NaN;
    const el = document.getElementById(id);
    if (!el) return NaN;
    return parseFloat(el.value);
}

// -----------------------------------------------------------------------
// Module-mutable state expected by the legacy module
// -----------------------------------------------------------------------
// Some legacy callers may inspect these. They are kept in sync each time
// `updateTaxRatesForYear` is invoked.
let PAYE_RATES, USC_RATES, PRSI_RATES, TAX_CREDITS;

function updateTaxRatesForYear(year) {
    const rates = engineUpdateTaxRatesForYear(year);
    PAYE_RATES = rates.PAYE_RATES;
    USC_RATES = rates.USC_RATES;
    PRSI_RATES = rates.PRSI_RATES;
    TAX_CREDITS = rates.TAX_CREDITS;
    return rates;
}

// Eagerly initialise to the page's selectedYear (if available) so that any
// late-bound script that reads PAYE_RATES sees a valid object.
updateTaxRatesForYear(currentYear());

// -----------------------------------------------------------------------
// Legacy-compatible wrappers
// -----------------------------------------------------------------------

function get2024PRSIRate() { return engineGet2024PRSIRate(current2024Period()); }
function get2025PRSIRate() { return engineGet2025PRSIRate(current2025Period()); }
function get2026PRSIRate() { return engineGet2026PRSIRate(current2026Period()); }

function calculatePAYE(grossIncome, status = 'single') {
    const year = currentYear();
    const manualCutOff = status === 'manual' ? readDomNumber('manualCutOffPoint') : undefined;
    return engineCalculatePAYE(grossIncome, { year, status, manualCutOff });
}

function calculatePAYEWithBreakdown(grossIncome, status = 'single') {
    const year = currentYear();
    const manualCutOff = status === 'manual' ? readDomNumber('manualCutOffPoint') : undefined;
    const manualTaxCredits = status === 'manual' ? readDomNumber('manualTaxCredits') : undefined;
    return engineCalculatePAYEWithBreakdown(grossIncome, {
        year,
        status,
        manualCutOff,
        manualTaxCredits,
        periodConfig: currentPeriodConfig()
    });
}

function calculateUSC(grossIncome) {
    return engineCalculateUSC(grossIncome, { year: currentYear() });
}

function calculateUSCWithBreakdown(grossIncome) {
    return engineCalculateUSCWithBreakdown(grossIncome, { year: currentYear() });
}

function calculatePRSI(grossIncome) {
    const year = currentYear();
    return engineCalculatePRSI(grossIncome, {
        year,
        period: yearPeriodForYear(year),
        periodConfig: currentPeriodConfig()
    });
}

function calculatePRSIWithBreakdown(grossIncome) {
    const year = currentYear();
    return engineCalculatePRSIWithBreakdown(grossIncome, {
        year,
        period: yearPeriodForYear(year),
        periodConfig: currentPeriodConfig()
    });
}

function calculateTaxCredits(status = 'single') {
    const year = currentYear();
    const manualTaxCredits = status === 'manual' ? readDomNumber('manualTaxCredits') : undefined;
    return engineCalculateTaxCredits({ year, status, manualTaxCredits });
}

function calculateNetFromGross(grossIncome, status = 'single') {
    const year = currentYear();
    const manualCutOff = status === 'manual' ? readDomNumber('manualCutOffPoint') : undefined;
    const manualTaxCredits = status === 'manual' ? readDomNumber('manualTaxCredits') : undefined;
    return engineCalculateNetFromGross(grossIncome, {
        year,
        status,
        period: yearPeriodForYear(year),
        periodConfig: currentPeriodConfig(),
        manualCutOff,
        manualTaxCredits
    });
}

function calculateGrossFromNet(targetNetIncome, status = 'single') {
    const year = currentYear();
    const manualCutOff = status === 'manual' ? readDomNumber('manualCutOffPoint') : undefined;
    const manualTaxCredits = status === 'manual' ? readDomNumber('manualTaxCredits') : undefined;
    return engineCalculateGrossFromNet(targetNetIncome, {
        year,
        status,
        period: yearPeriodForYear(year),
        periodConfig: currentPeriodConfig(),
        manualCutOff,
        manualTaxCredits
    });
}

// Legacy `convertFromAnnual` / `convertToAnnual` may already be defined by
// the page (index.html / payroll/index.html). We do NOT overwrite them —
// they read the page's own `activeTab` and `tabConfig`. The pure engine
// uses its own normalised period helpers internally.

// -----------------------------------------------------------------------
// Expose to the target (window / globalThis)
// -----------------------------------------------------------------------

const publicApi = {
    TAX_RATES,
    updateTaxRatesForYear,
    roundToThree,
    roundToTwo,
    get2024PRSIRate,
    get2025PRSIRate,
    get2026PRSIRate,
    calculatePAYE,
    calculatePAYEWithBreakdown,
    calculateUSC,
    calculateUSCWithBreakdown,
    calculatePRSI,
    calculatePRSIWithBreakdown,
    calculateTaxCredits,
    calculateNetFromGross,
    calculateGrossFromNet,
    formatCurrency,
    formatNumber,
    formatPercentage,
    // Pure helpers, exposed for future migrations
    ratesForYear,
    normalisePeriodConfig,
    engineConvertFromAnnual,
    engineConvertToAnnual
};

for (const [key, value] of Object.entries(publicApi)) {
    // Don't shadow page-defined helpers that pre-exist on window.
    if (key === 'engineConvertFromAnnual' || key === 'engineConvertToAnnual') {
        target[key] = value;
        continue;
    }
    // For PAYE/USC/PRSI calc names: always overwrite — we are the source of truth.
    target[key] = value;
}

// Mirror the live rate references each time the year changes upstream.
// Re-expose a getter-style property so reads always see the latest values.
Object.defineProperty(target, 'PAYE_RATES', { configurable: true, get: () => PAYE_RATES });
Object.defineProperty(target, 'USC_RATES', { configurable: true, get: () => USC_RATES });
Object.defineProperty(target, 'PRSI_RATES', { configurable: true, get: () => PRSI_RATES });
Object.defineProperty(target, 'TAX_CREDITS', { configurable: true, get: () => TAX_CREDITS });

export default publicApi;
