// Pure USC calculations (legacy js/calculator-core.js L180–237).

import { ratesForYear } from './rates.js';
import { roundToThree } from './rounding.js';

/**
 * @param {number} grossIncome
 * @param {object} opts
 * @param {string|number} opts.year
 * @returns {number}
 */
export function calculateUSC(grossIncome, { year } = {}) {
  if (grossIncome < 13000) return 0;
  const { USC_RATES } = ratesForYear(year);

  let usc = 0;
  let remainingIncome = grossIncome;
  for (const band of USC_RATES) {
    if (remainingIncome <= 0) break;
    const taxableInThisBand = Math.min(remainingIncome, band.max - band.min);
    usc += taxableInThisBand * band.rate;
    remainingIncome -= taxableInThisBand;
  }
  return roundToThree(usc);
}

/**
 * @param {number} grossIncome
 * @param {object} opts
 * @param {string|number} opts.year
 */
export function calculateUSCWithBreakdown(grossIncome, { year } = {}) {
  if (grossIncome < 13000) {
    return { total: 0, bands: [], exempt: true, grossIncome };
  }
  const { USC_RATES } = ratesForYear(year);

  let totalUSC = 0;
  let remainingIncome = grossIncome;
  const bands = [];
  for (const band of USC_RATES) {
    if (remainingIncome <= 0) break;
    const taxableInThisBand = Math.min(remainingIncome, band.max - band.min);
    const uscForBand = roundToThree(taxableInThisBand * band.rate);
    bands.push({
      min: band.min,
      max: band.max === Infinity ? 'Above' : band.max,
      rate: band.rate,
      taxableAmount: roundToThree(taxableInThisBand),
      uscAmount: uscForBand
    });
    totalUSC += uscForBand;
    remainingIncome -= taxableInThisBand;
  }
  return { total: roundToThree(totalUSC), bands, exempt: false, grossIncome };
}
